import requests

def test_non_admin_role_forbidden_from_viewing_payroll_run(
    employee_auth_token, base_url, get_existing_payroll_run_id
):
    payroll_run_id = get_existing_payroll_run_id()
    headers = {"Authorization": f"Bearer {employee_auth_token}"}

    response = requests.get(
        f"{base_url}/payroll-runs/{payroll_run_id}",
        headers=headers,
        timeout=10
    )

    assert response.status_code == 403, (
        f"Expected 403, got {response.status_code}: {response.text}"
    )
    body = response.json()
    assert "error" in body or "message" in body, (
        "Response body should contain an error or message field"
    )

import requests

def test_admin_views_payroll_run_with_minimum_boundary_id(
    admin_auth_token, base_url, ensure_payroll_run_id_exists
):
    payroll_run_id = 1
    ensure_payroll_run_id_exists(payroll_run_id)
    headers = {"Authorization": f"Bearer {admin_auth_token}"}

    response = requests.get(
        f"{base_url}/payroll-runs/{payroll_run_id}",
        headers=headers,
        timeout=10
    )

    assert response.status_code == 200, (
        f"Expected 200 for id=1, got {response.status_code}: {response.text}"
    )
    body = response.json()
    assert int(body.get("id")) == payroll_run_id, (
        f"Expected id=1 in response, got {body.get('id')}"
    )

import requests

def test_admin_views_payroll_run_with_invalid_id_returns_400(
    admin_auth_token, base_url
):
    invalid_id = "invalid-id"
    headers = {"Authorization": f"Bearer {admin_auth_token}"}

    response = requests.get(
        f"{base_url}/payroll-runs/{invalid_id}",
        headers=headers,
        timeout=10
    )

    assert response.status_code == 400, (
        f"Expected 400 for invalid id, got {response.status_code}: {response.text}"
    )
    body = response.json()
    assert "error" in body or "errors" in body or "message" in body, (
        "Response body must contain validation error details"
    )
